import requests

response = requests.post(
    'https://api.pinelabs.com/v1/sdk/init',
    headers={
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_API_KEY'
    },
    json={
        'transport_preference': ['USB', 'BLUETOOTH'],
        'default_timeout_ms': 60000,
        'log_level': 'INFO'
    }
)
print(response.json())
